/**
 * Types and schema definitions for JoSAA/CSAB historical cutoff data (2021–2025).
 */

export type CutoffYear = 2021 | 2022 | 2023 | 2024 | 2025;

export type CutoffRound = 1 | 2 | 3 | 4 | 5 | 6;

export type Category =
  | 'OPEN'
  | 'OBC-NCL'
  | 'SC'
  | 'ST'
  | 'EWS'
  | 'OPEN (PwD)'
  | 'OBC-NCL (PwD)'
  | 'SC (PwD)'
  | 'ST (PwD)'
  | 'EWS (PwD)';

export type Gender =
  | 'Gender-Neutral'
  | 'Female-only (including Supernumerary)';

export type Quota =
  | 'AI' // All India
  | 'HS' // Home State
  | 'OS' // Other State
  | 'AP' // Andhra Pradesh (for state-specific cases)
  | 'GO' // Goa State-specific
  | 'JK' // Jammu & Kashmir
  | 'LA'; // Ladakh

export interface CutoffHistoryRecord {
  /**
   * Unique identifier of the institute (e.g. 'iit-bombay')
   */
  instituteId: string;

  /**
   * Official branch/program code (e.g. 'CSE', 'ECE')
   */
  branchCode: string;

  /**
   * Academic year of admission (2021-2025)
   */
  year: CutoffYear;

  /**
   * Round number of the seat allocation process (1-6)
   */
  round: CutoffRound;

  /**
   * Seat allocation category
   */
  category: Category;

  /**
   * Target gender pool for the seat
   */
  gender: Gender;

  /**
   * State quota category of seat allocation
   */
  quota: Quota;

  /**
   * Opening rank for the specified category/quota/gender pool
   */
  openingRank: number;

  /**
   * Closing rank for the specified category/quota/gender pool
   */
  closingRank: number;
}

